+                        } else {
+                            (Some(selected.id.clone()), None)
+                        };
+
+                        // No-op if already at target leaf.
+                        if selector.current_leaf_id.as_deref() == new_leaf_id.as_deref() {
+                            self.status_message = Some("Already on that branch".to_string());
+                            self.tree_ui = None;
+                            return None;
+                        }
