+                        let pending = PendingTreeNavigation {
+                            session_id,
+                            old_leaf_id,
+                            selected_entry_id: selected.id,
+                            new_leaf_id,
+                            editor_text,
+                            entries_to_summarize,
+                            summary_from_id,
